option.value:
/* Ocultar el checkbox original */
li.task-list-item input[type="checkbox"] {
  -webkit-appearance: none; /* Ocultarlo en renderizadores basados en Webkit/Chromium */
  appearance: none;
  margin: 0 0.4em 0 0; /* Ajustar el espaciado */
}

/* Mostrar un cuadro vacío para tareas no completadas */
li.task-list-item input[type="checkbox"]::before {
  content: "⬜️";
  font-size: 1.1em; /* Ajustar tamaño del emoji */
}

/* Mostrar el emoji de check para tareas completadas y colorear el texto */
li.task-list-item input[type="checkbox"]:checked::before {
  content: "✅";
}
